import{_ as r,o as e,c as a,a2 as o}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"💡 光通訊追蹤日報 — 2026年5月28日（週四）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/光通訊研究/追蹤日誌/光通訊追蹤_2026-05-28.md","filePath":"Deep32Q知識庫/產業洞察/光通訊研究/追蹤日誌/光通訊追蹤_2026-05-28.md"}'),n={name:"Deep32Q知識庫/產業洞察/光通訊研究/追蹤日誌/光通訊追蹤_2026-05-28.md"};function i(l,t,s,c,h,d){return e(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="💡-光通訊追蹤日報-—-2026年5月28日-週四" tabindex="-1">💡 光通訊追蹤日報 — 2026年5月28日（週四） <a class="header-anchor" href="#💡-光通訊追蹤日報-—-2026年5月28日-週四" aria-label="Permalink to &quot;💡 光通訊追蹤日報 — 2026年5月28日（週四）&quot;">​</a></h1><blockquote><p><strong>查詢時間</strong>：TST 05:00 (2026-05-28 05:00 = 2026-05-27 21:00 UTC) <strong>昨日敘事延續</strong>：NVIDIA $65億光子投資、台積電 COUPE on Substrate H2 量產、Broadcom Taurus 400G/lane DSP → 2026 商轉元年加速推進</p></blockquote><hr><h2 id="🔴-即時指標-4-項檢查" tabindex="-1">🔴 即時指標 4 項檢查 <a class="header-anchor" href="#🔴-即時指標-4-項檢查" aria-label="Permalink to &quot;🔴 即時指標 4 項檢查&quot;">​</a></h2><h3 id="指標1️⃣-nvidia-cpo-spectrum-x-quantum-x-—-🟢-積極推進" tabindex="-1">指標1️⃣ NVIDIA CPO/Spectrum-X/Quantum-X — 🟢 積極推進 <a class="header-anchor" href="#指標1️⃣-nvidia-cpo-spectrum-x-quantum-x-—-🟢-積極推進" aria-label="Permalink to &quot;指標1️⃣ NVIDIA CPO/Spectrum-X/Quantum-X — 🟢 積極推進&quot;">​</a></h3><p><strong>最新動態</strong>：</p><ul><li><strong>資本投入升級</strong>：總計逾 <strong>$65 億</strong>光子/CPO 投資（較先前 $40 億大幅增加） <ul><li>$20 億 → Lumentum（InP 雷射晶片產能鎖定）</li><li>$20 億 → Coherent（先進光學元件）</li><li>其餘投入其他光子技術</li></ul></li><li><strong>產品路線圖</strong>： <ul><li>Quantum-X Photonics / Spectrum-X Photonics：預計 2026 H2 商用，409.6 Tb/s 頻寬，功耗降低 3.5x</li><li>Spectrum-X Ethernet Photonics Switch：直接整合 1.6T SiPho 光引擎，雙倍頻寬至 102.4Tb/s/ASIC</li><li>NVL576 scale-up：預計約 2027 年導入 CPO</li></ul></li><li><strong>NVIDIA FQ1 財報</strong>（5月發布）：CFO Colette Kress 提及矽光子技術合作擴展</li><li><strong>戰略意義</strong>：從傳統可插拔光模組快速轉向深度 CPO 整合，光通訊與 GPU 同等戰略地位</li></ul><p>📎 來源：<a href="https://www.techinsights.com/blog/analysis-nvidia-bets-big-photonics-and-cpo" target="_blank" rel="noreferrer">TechInsights</a> · <a href="https://nvidianews.nvidia.com/news/nvidia-announces-financial-results-for-first-quarter-fiscal-2027" target="_blank" rel="noreferrer">NVIDIA News</a> · <a href="https://io-fund.com/ai-stocks/nvidia-4b-optical-strategy-cpo-ai-data-centers" target="_blank" rel="noreferrer">IO Fund</a> · <a href="https://www.tomshardware.com/networking/nvidia-outlines-plans-for-using-light-for-communication-between-ai-gpus-by-2026-silicon-photonics-and-co-packaged-optics-may-become-mandatory-for-next-gen-ai-data-centers" target="_blank" rel="noreferrer">Tom&#39;s Hardware</a> （T: 05:00 TST）</p><hr><h3 id="指標2️⃣-broadcom-cpo-dsp-技術動態-—-🟢-新產品-標準化" tabindex="-1">指標2️⃣ Broadcom CPO/DSP 技術動態 — 🟢 新產品 + 標準化 <a class="header-anchor" href="#指標2️⃣-broadcom-cpo-dsp-技術動態-—-🟢-新產品-標準化" aria-label="Permalink to &quot;指標2️⃣ Broadcom CPO/DSP 技術動態 — 🟢 新產品 + 標準化&quot;">​</a></h3><p><strong>最新動態</strong>：</p><ul><li><strong>OCI MSA 標準化</strong>：Broadcom 牽頭成立 Optical Compute Interconnect MSA，建立開放多供應商規格 <ul><li>GEN1：4λ x 50Gbps NRZ（200Gbps/direction）</li><li>GEN2：400Gbps/direction 雙向</li><li>藍圖：3.2Tbps/fiber</li></ul></li><li><strong>Taurus™ DSP</strong>：業界首款 400G/lane 光 DSP，支援 1.6T 收發器 + 未來 3.2T</li><li><strong>Tomahawk 6 - Davisson</strong>：102.4Tbps CPO Ethernet switch，2025 Q4 開始出貨</li><li><strong>Meta 驗證</strong>：在高溫實驗室完成 100 萬小時無中斷連結測試</li><li><strong>最新（5/26）</strong>：發布 BCM68850 — 業界首款 50G ITU-PON 家用閘道 SoC，內建 NPU + Wi-Fi 8</li></ul><p>📎 來源：<a href="https://www.broadcom.com/company/news/product-releases/optical-scale-up-consortium-established-to-create-an-open-specification-for-ai-infrastructure" target="_blank" rel="noreferrer">Broadcom</a> · <a href="https://www.broadcom.com/blog/ofc-2026-broadcom-paves-the-path-for-the-200t-ai-era" target="_blank" rel="noreferrer">Broadcom Blog</a> · <a href="https://www.globenewswire.com/news-release/2026/05/26/3301129/19933/en/Broadcom-Accelerates-the-AI-Era-with-the-Industry-s-First-End-to-End-50G-PON-Edge-AI-Portfolio.html" target="_blank" rel="noreferrer">GlobeNewsWire</a> （T: 05:00 TST）</p><hr><h3 id="指標3️⃣-台積電先進封裝光通訊相關-—-🟢-量產準備就緒" tabindex="-1">指標3️⃣ 台積電先進封裝光通訊相關 — 🟢 量產準備就緒 <a class="header-anchor" href="#指標3️⃣-台積電先進封裝光通訊相關-—-🟢-量產準備就緒" aria-label="Permalink to &quot;指標3️⃣ 台積電先進封裝光通訊相關 — 🟢 量產準備就緒&quot;">​</a></h3><p><strong>最新動態</strong>：</p><ul><li><strong>COUPE on Substrate</strong>：2026 技術論壇（5/14）宣布 <strong>H2 量產</strong>，將 CPO 從晶片擴展到基板層</li><li><strong>PIC 產能目標</strong>：2027 Q1 達每月 10,000 片晶圓</li><li><strong>micro-ring modulator</strong>：全球首款 200Gbps COUPE 微環調變器已進入量產，BER &lt; 10⁻⁸</li><li><strong>SoIC-X 堆疊</strong>：直接將電子晶片堆疊於光子晶片上方，功耗改善 5-10x，延遲降低 10-20x</li><li><strong>CoWoS 整合</strong>：COUPE 規劃整合入 CoWoS 封裝，形成完整 CPO 架構</li><li><strong>供應鏈</strong>：若 CPO 成為主流，NVIDIA 可能提前鎖定台積電高階基板產能</li></ul><p>📎 來源：<a href="https://www.trendforce.com/news/2026/04/01/news-silicon-photonics-race-intensifies-as-tsmc-targets-2026-coupe-production-samsung-eyes-2029-cpo-turnkey/" target="_blank" rel="noreferrer">TrendForce</a> · <a href="https://bits-chips.com/article/tsmc-pushes-silicon-photonics-platform-to-mass-production/" target="_blank" rel="noreferrer">Bits &amp; Chips</a> · <a href="https://borecraft.com/2026/05/14/tsmcs-coupe-is-the-keyword-from-the-2026-technology-forum/" target="_blank" rel="noreferrer">Borecraft</a> （T: 05:00 TST）</p><hr><h3 id="指標4️⃣-csp-資本支出公告-—-🟢-ai-capex-持續飆升" tabindex="-1">指標4️⃣ CSP 資本支出公告 — 🟢 AI Capex 持續飆升 <a class="header-anchor" href="#指標4️⃣-csp-資本支出公告-—-🟢-ai-capex-持續飆升" aria-label="Permalink to &quot;指標4️⃣ CSP 資本支出公告 — 🟢 AI Capex 持續飆升&quot;">​</a></h3><ul><li>全球科技巨頭（MSFT/GOOGL/AMZN/META）資本支出預算一再上修</li><li>GB300 伺服器大量出貨中，萬卡級叢集對光模組需求高達數萬顆</li><li>OCS 市場規模：~$4 億 → ~$40 億（10x）</li><li>CPO 市場規模：上看 $150 億</li><li>TrendForce 預測 2030 年 CPO 滲透率達 35%</li></ul><p>📎 來源：<a href="https://blog.growin.tv/ai-server-stocks-2026/" target="_blank" rel="noreferrer">Growin TV</a> · <a href="https://yieldwerx.com/blog/2026-photonics-optical-io-trends-challenges/" target="_blank" rel="noreferrer">YieldWerx</a> （T: 05:00 TST）</p><hr><h2 id="🟡-台灣供應鏈動態" tabindex="-1">🟡 台灣供應鏈動態 <a class="header-anchor" href="#🟡-台灣供應鏈動態" aria-label="Permalink to &quot;🟡 台灣供應鏈動態&quot;">​</a></h2><h3 id="聯亞光電-3081-—-🔴-營收爆發" tabindex="-1">聯亞光電 (3081) — 🔴 營收爆發 <a class="header-anchor" href="#聯亞光電-3081-—-🔴-營收爆發" aria-label="Permalink to &quot;聯亞光電 (3081) — 🔴 營收爆發&quot;">​</a></h3><ul><li><strong>2026 Q1</strong>：稅後淨利 3.18 億，EPS 3.44 元（去年同期 0.56 元），年增 6 倍</li><li><strong>4 月營收</strong>：3.95 億（月增 15.2%，年增 115.4%），<strong>歷史新高</strong></li><li><strong>累計前四月</strong>：~13 億，年增 103.7%</li><li><strong>InP 供應</strong>：與日本供應商簽訂 5 年 InP 基板長期供貨合約</li><li><strong>Capex</strong>：上修至 13.15 億，提前布局 2027 H2 後需求</li><li><strong>展望</strong>：Q2 營收季增幅優於去年 Q4 的 16%</li></ul><p>📎 來源：<a href="https://www.ttv.com.tw/finance/view/052026060927296778193AE74F16AD35396B786F6D036ADC/588" target="_blank" rel="noreferrer">TTV Finance</a> · <a href="https://info.ifa.ai/tw-stock/3081/revenue" target="_blank" rel="noreferrer">iFA.ai</a> （T: 05:00 TST）</p><h3 id="光聖-6442-—-🟢-穩定成長" tabindex="-1">光聖 (6442) — 🟢 穩定成長 <a class="header-anchor" href="#光聖-6442-—-🟢-穩定成長" aria-label="Permalink to &quot;光聖 (6442) — 🟢 穩定成長&quot;">​</a></h3><ul><li><strong>2025 全年</strong>：營收 105.27 億（+64%），毛利率 57.74%，EPS 23.46 元</li><li><strong>2026 Q1</strong>：營收 27.05 億（+29%），毛利率 55.41%，EPS 7.82 元（歷史次高）</li><li><strong>股利</strong>：現金 11.8 元（上市新高）</li><li><strong>合聖 FAU</strong>：送樣美系大廠認證中，2026 H2 小量試產，2027-28 放量</li><li><strong>IET-KY 結盟</strong>：布局 InP 磊晶材料</li></ul><p>📎 來源：<a href="https://technews.tw/2026/05/26/ezconn-fau-samples-us-manufacturer-certification-h2-trial-production/" target="_blank" rel="noreferrer">TechNews</a> · <a href="https://news.cnyes.com/news/id/6442998" target="_blank" rel="noreferrer">CnYES</a> （T: 05:00 TST）</p><h3 id="上詮-3363-—-🟡-短期承壓" tabindex="-1">上詮 (3363) — 🟡 短期承壓 <a class="header-anchor" href="#上詮-3363-—-🟡-短期承壓" aria-label="Permalink to &quot;上詮 (3363) — 🟡 短期承壓&quot;">​</a></h3><ul><li><strong>2026 Q1</strong>：營收 3.82 億，稅後淨損 1.07 億，EPS -0.98 元</li><li><strong>4 月營收</strong>：1.28 億（月增 9.1%，年減 37.3%）</li><li><strong>FAU 產品</strong>：與台積電合作研發 3 年+，規格推進至 1.6T/3.2T</li><li><strong>展望</strong>：2026 H2 開始出貨 1.6T/3.2T FAU，營收貢獻集中於 2026 底至 2027</li><li><strong>5/29</strong>：參加 Morgan Stanley Asia AI Summit</li></ul><p>📎 來源：<a href="https://news.cnyes.com/news/id/6445438" target="_blank" rel="noreferrer">CnYES</a> · <a href="https://money.udn.com/money/story/5607/9522682" target="_blank" rel="noreferrer">UDN Money</a> （T: 05:00 TST）</p><h3 id="智邦-2345-—-⏳-待觀察" tabindex="-1">智邦 (2345) — ⏳ 待觀察 <a class="header-anchor" href="#智邦-2345-—-⏳-待觀察" aria-label="Permalink to &quot;智邦 (2345) — ⏳ 待觀察&quot;">​</a></h3><ul><li>光通訊解決方案持續開發，本日無個股更新</li></ul><hr><h2 id="📊-產業趨勢摘要表" tabindex="-1">📊 產業趨勢摘要表 <a class="header-anchor" href="#📊-產業趨勢摘要表" aria-label="Permalink to &quot;📊 產業趨勢摘要表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>趨勢</th><th>狀態</th><th>說明</th></tr></thead><tbody><tr><td>銅退光進</td><td>🔴 確定性高</td><td>銅線傳輸物理極限逼近，資料中心全面轉向光互連</td></tr><tr><td>2026 商轉元年</td><td>🔴 正在發生</td><td>CPO 技術從理論走向現實，多個平台進入商用階段</td></tr><tr><td>OCI-MSA</td><td>🟢 建立完成</td><td>Broadcom 牽頭開放多供應商生態</td></tr><tr><td>1.6T 商業化</td><td>🟢 加速推進</td><td>Broadcom Taurus 400G/lane DSP + 台積電 COUPE 量產</td></tr><tr><td>800G 成熟量產</td><td>✅ 已達成</td><td>各廠均已有成熟產品線</td></tr><tr><td>NVIDIA 光子投資</td><td>🔴 升級至 $65 億</td><td>較先前 $40 億大幅增加</td></tr></tbody></table><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>TechInsights (2026-05): NVIDIA $65 億光子/CPO 戰略分析</li><li>NVIDIA News (2026-05): FQ1 FY2027 財報 — 矽光子合作擴展</li><li>Broadcom (2026-05): OCI MSA + Taurus DSP + BCM68850</li><li>TrendForce (2026-04): 台積電 COUPE on Substrate 量產時程</li><li>TTV Finance (2026-05): 聯亞 3081 Q1 營收爆發</li><li>TechNews (2026-05-26): 光聖合聖 FAU 認證進度</li><li>CnYES (2026-05): 上詮 3363 營運概況</li><li>YieldWerx (2026-05): 2026 Photonics 趨勢報告</li></ol>',41)])])}const p=r(n,[["render",i]]);export{u as __pageData,p as default};
